// Get digest posts from first HTTP request
const digestData = $node["Get Newsletter Digest"].json.digest;
const posts = digestData.posts;
const subscriber = $json;

// Build HTML email content
let htmlContent = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 20px; }
    h1 { color: #333; border-bottom: 3px solid #007bff; padding-bottom: 10px; }
    .post { margin: 25px 0; padding: 20px; background: #f8f9fa; border-left: 4px solid #007bff; }
    .post h2 { margin-top: 0; color: #007bff; }
    .post h2 a { color: #007bff; text-decoration: none; }
    .post h2 a:hover { text-decoration: underline; }
    .excerpt { color: #555; line-height: 1.6; margin: 10px 0; }
    .meta { color: #666; font-size: 14px; margin-top: 10px; }
    .footer { margin-top: 40px; padding-top: 20px; border-top: 1px solid #ddd; text-align: center; color: #999; font-size: 12px; }
    .footer a { color: #007bff; text-decoration: none; }
  </style>
</head>
<body>
  <h1>🚀 Weekly Blog Digest</h1>
  <p>Hi there! Here are the top posts from this week:</p>
`;

// Add each post
posts.forEach((post, index) => {
  htmlContent += `
  <div class="post">
    <h2><a href="${post.url}">${post.title}</a></h2>
    <p class="excerpt">${post.excerpt}</p>
    <div class="meta">By ${post.author} | ${post.views} views | ${new Date(post.published_at).toLocaleDateString()}</div>
  </div>
  `;
});

// Add footer with unsubscribe
htmlContent += `
  <div class="footer">
    <p>You're receiving this because you subscribed to our newsletter.</p>
    <p>
      <a href="${subscriber.unsubscribe_url}">Unsubscribe</a> | 
      <a href="https://yourblog.com">Visit Blog</a>
    </p>
  </div>
</body>
</html>
`;

return {
  json: {
    to: subscriber.email,
    subject: `Weekly Digest - ${posts.length} New Posts`,
    html: htmlContent
  }
};
